from __future__ import annotationsimport pytestfrom src.modules.settings_schema import (    SettingFieldSchema,    SettingsGroupSchema,    SettingsSchemaCollection,    SettingsSchemaError,)def test_build_default_payload_returns_group_defaults() -> None:    collection = SettingsSchemaCollection(        groups=(            SettingsGroupSchema(                code="extract",                title="Извлечение",                fields=(                    SettingFieldSchema(key="enabled", type="bool", default=True, label="Включен"),                    SettingFieldSchema(                        key="mode",                        type="select",                        default="skip",                        label="Режим",                        options=(("skip", "Пропустить"), ("copy", "Скопировать")),                    ),                ),            ),        )    )    assert collection.build_default_payload() == {        "extract": {            "enabled": True,            "mode": "skip",        }    }def test_normalize_payload_applies_defaults_and_type_rules() -> None:    collection = SettingsSchemaCollection(        groups=(            SettingsGroupSchema(                code="extract",                title="Извлечение",                fields=(                    SettingFieldSchema(key="enabled", type="bool", default=True, label="Включен"),                    SettingFieldSchema(key="retries", type="int", default=3, label="Повторы"),                    SettingFieldSchema(                        key="mode",                        type="select",                        default="skip",                        label="Режим",                        options=(("skip", "Пропустить"), ("copy", "Скопировать")),                    ),                ),            ),        )    )    assert collection.normalize_payload(        {            "extract": {                "enabled": 0,                "retries": "-5",                "mode": "invalid",            }        }    ) == {        "extract": {            "enabled": False,            "retries": 3,            "mode": "skip",        }    }def test_apply_values_returns_values_collection() -> None:    collection = SettingsSchemaCollection(        groups=(            SettingsGroupSchema(                code="extract",                title="Извлечение",                fields=(                    SettingFieldSchema(key="enabled", type="bool", default=True, label="Включен"),                    SettingFieldSchema(                        key="mode",                        type="select",                        default="skip",                        label="Режим",                        options=(("skip", "Пропустить"), ("copy", "Скопировать")),                    ),                ),            ),        )    )    values = collection.apply_values(        {            "extract": {                "enabled": "false",                "mode": "copy",            }        }    )    assert values.get_group_value("extract", "enabled") is False    assert values.get_group_value("extract", "mode") == "copy"def test_apply_values_raises_on_invalid_select_value() -> None:    collection = SettingsSchemaCollection(        groups=(            SettingsGroupSchema(                code="extract",                title="Извлечение",                fields=(                    SettingFieldSchema(                        key="mode",                        type="select",                        default="skip",                        label="Режим",                        options=(("skip", "Пропустить"), ("copy", "Скопировать")),                    ),                ),            ),        )    )    with pytest.raises(SettingsSchemaError):        collection.apply_values(            {                "extract": {                    "mode": "invalid",                }            }        )def test_collection_raises_on_duplicated_group_codes() -> None:    group = SettingsGroupSchema(code="extract", title="Извлечение")    with pytest.raises(SettingsSchemaError):        SettingsSchemaCollection(groups=(group, group))def test_settings_group_schema_accepts_optional_description() -> None:    """SettingsGroupSchema accepts optional description; default is empty string."""    group_without = SettingsGroupSchema(code="a", title="A", fields=())    assert group_without.description == ""    group_with_desc = SettingsGroupSchema(        code="b", title="B", description="Пояснение для группы", fields=()    )    assert group_with_desc.description == "Пояснение для группы"